import json, csv, openai, numpy as np
from sklearn.metrics.pairwise import cosine_similarity

# --- 1. Load your intent examples ---
with open('intents.json') as f:
    intents = json.load(f)  # {"intent_name": ["example1", "example2", ...]}

client = openai.OpenAI()  # set OPENAI_API_KEY in env

def embed(text):
    resp = client.embeddings.create(model="text-embedding-3-small", input=[text])
    return np.array(resp.data[0].embedding)

# --- 2. Build intent centroids ---
centroids = {}
for intent, examples in intents.items():
    vecs = np.array([embed(e) for e in examples])
    centroids[intent] = vecs.mean(axis=0)

def classify(utterance):
    uv = embed(utterance)
    scores = {k: cosine_similarity([uv],[v])[0][0] for k,v in centroids.items()}
    return max(scores, key=scores.get), scores

# --- 3. Run on test utterances and log ---
test_cases = [
    {"text": "I want to book a demo", "true_intent": "schedule_demo"},
    # add more...
]

with open('error_log.csv','w',newline='') as f:
    writer = csv.DictWriter(f, fieldnames=['text','true_intent','predicted_intent','correct','scores'])
    writer.writeheader()
    for tc in test_cases:
        pred, scores = classify(tc['text'])
        writer.writerow({
            'text': tc['text'],
            'true_intent': tc['true_intent'],
            'predicted_intent': pred,
            'correct': pred == tc['true_intent'],
            'scores': str(scores)
        })

print('Done. Review error_log.csv for your deliberate-practice loop.')
